import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { ApiResponse, OrdenCompra } from '../models/interfaces';

@Injectable({ providedIn: 'root' })
export class OrdencompraService {
  private base = 'http://localhost:3007/api/ordencompra';

  constructor(private http: HttpClient) {}

  getAll(): Observable<ApiResponse<OrdenCompra[]>> {
    return this.http.get<ApiResponse<OrdenCompra[]>>(this.base);
  }

  getByFolio(folio: number): Observable<ApiResponse<OrdenCompra[]>> {
    return this.http.get<ApiResponse<OrdenCompra[]>>(`${this.base}/folio/${folio}`);
  }

  getByEstatus(estatus: string): Observable<ApiResponse<OrdenCompra[]>> {
    return this.http.get<ApiResponse<OrdenCompra[]>>(`${this.base}/estatus/${estatus}`);
  }
}
